"use client";

import { createClient } from "@/utils/client";

import { difficultyColor } from "@/constants/constants";
import Image from "next/image";
import { useState, useEffect } from "react";

import type { Recipe } from "@/types/types";
import type { Ingredient } from "@/types/types";

type Props = {
  recipe: Recipe;
};

export default function RecipeDetails({ recipe }: Props) {
  const [ingredientIds, setIngredientIds] = useState<number[]>([]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);

  const client = createClient();

  useEffect(() => {
    async function getIngredients() {
      const { data, error } = await client
        .from("recipeingredients")
        .select("id")
        .eq("recipe_id", recipe.id);

      if (error) {
        console.log("An Error occured: ", error.message);
      }

      if (data) {
        const ids = data.map((item) => item.id);
        setIngredientIds(ids);
      }
    }

    getIngredients();
  }, [recipe]);

  useEffect(() => {
    async function getNames() {
      const { data, error } = await client
        .from("ingredients")
        .select("*")
        .in("id", ingredientIds);

      if (error) {
        console.log("An error happened", error.message);
      }

      if (data) {
        setIngredients(data);
      }
    }

    getNames();
  }, [ingredientIds]);

  return (
    <>
      <div className="relative w-full h-[60vh]">
        <Image
          src={recipe.avatar_url}
          alt={recipe.name}
          fill
          className="object-cover"
          priority
        />

        <div className="absolute inset-0 bg-linear-to-t from-black/90 via-black/30 to-transparent" />

        <div className="absolute inset-0 flex items-end">
          <div className="w-full flex justify-between items-end p-6 md:p-10 text-white">
            <div>
              <h1 className="text-4xl md:text-5xl font-bold drop-shadow-lg">
                {recipe.name}
              </h1>

              <p className="mt-2 max-w-xl text-sm md:text-base text-white/90">
                {recipe.description}
              </p>
            </div>

            <div className="text-right space-y-2 flex flex-row gap-8">
              <span
                className={`inline-block px-3 py-1 rounded-full text-sm font-medium ${
                  difficultyColor[recipe.difficulty]
                }`}
              >
                {recipe.difficulty}
              </span>

              <p className="text-sm md:text-base">
                ⏱ Prep: {recipe.prep_time} min
              </p>

              <p className="text-sm md:text-base">
                🍳 Cook: {recipe.cooking_time} min
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="place-self-center mt-8">
        <h2 className="text-2xl font-bold underline decoration-gray-700">
          Ingredients
        </h2>
        <hr />

        {ingredients.map((ingredient) => (
          <h1 key={ingredient.id}>{ingredient.name}</h1>
        ))}

        <h2 className="text-2xl font-bold">Steps</h2>
        <p>…</p>
      </div>
    </>
  );
}
